import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { LowStockRow } from '../../core/models';

/**
 * Low-stock report (manager only). Items whose total on-hand has fallen below
 * their reorder threshold, so managers know what to replenish.
 */
@Component({
  selector: 'app-low-stock-report',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './low-stock-report.component.html',
  styleUrl: './low-stock-report.component.css',
})
export class LowStockReportComponent {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly rows = signal<LowStockRow[]>([
    { id: 'i6', sku: 'SKU-1006', name: 'Rubber Gasket 50mm', unit: 'pcs', onHand: 0, reorderAt: 80 },
    { id: 'i3', sku: 'SKU-1003', name: 'PVC Pipe 20mm', unit: 'pcs', onHand: 12, reorderAt: 50 },
    { id: 'i8', sku: 'SKU-1008', name: 'Paint Can White 5L', unit: 'cans', onHand: 18, reorderAt: 25 },
    { id: 'i2', sku: 'SKU-1002', name: 'Copper Wire 2mm', unit: 'm', onHand: 85, reorderAt: 200 },
  ]);

  deficit(r: LowStockRow): number {
    return Math.max(0, r.reorderAt - r.onHand);
  }
}
